mapper.update:
update course_evaluation
set rating = #{rating}, content = #{content}, teacher_evaluation = #{teacher_evaluation}, evaluation_time = #{evaluation_time}
where student_id = #{student_id} and course_id = #{course_id}

mapper.select:
select * from course_evaluation
where course_id = #{course_id}
order by evaluation_time desc

select * from course_evaluation
where teacher_id = #{teacher_id}
order by evaluation_time desc
